/**
 * MAGI Code — AI Agent Communication
 * Handles API calls with streaming and tool call parsing
 */
import https from 'https';
import http from 'http';
import { URL } from 'url';
import { getSystemPrompt } from './config.js';
import { executeTool, needsConfirmation } from './tools.js';
import {
  renderResponseStart, renderResponseEnd, renderResponseLine,
  renderToolCall, renderToolResult, renderDiff, renderError, colors,
} from './ui.js';
import ora from 'ora';

/**
 * Send a message to the AI and handle the response with streaming
 */
export async function sendMessage(config, session, userMessage, { onToolConfirm }) {
  const agentInfo = config.agents[config.agent] || config.agents.magi;

  // Add user message to session
  session.addMessage('user', userMessage);

  // Build messages for API
  const systemPrompt = getSystemPrompt(config);
  const apiMessages = session.getApiMessages();

  // Start response display
  // Show agent name header only (no box yet)
  const header = colors.primary('\n  ' + agentInfo.emoji + ' ' + agentInfo.name + '\n');
  process.stdout.write(header);
  process.stdout.write(colors.dim('  '));

  let fullResponse = '';

  try {
    fullResponse = await streamCompletion(config, systemPrompt, apiMessages);
  } catch (err) {
    renderResponseLine(colors.error(`API Error: ${err.message}`));
    // response done

    if (err.message.includes('API key')) {
      console.log(colors.warning('\n  Set your API key:'));
      console.log(colors.dim('  export MAGI_API_KEY=sk-ant-...\n'));
    }
    return;
  }

  // Parse and handle tool calls
  const { text, toolCalls } = parseResponse(fullResponse);

  // Display text portion
  if (text.trim()) {
    // Clean newline after streaming
    process.stdout.write('\n\n');
  }

  // Handle tool calls
  if (toolCalls.length > 0) {
    for (const tc of toolCalls) {
      console.log(renderToolCall(tc.name, tc.args));

      // Ask for confirmation if needed
      if (needsConfirmation(tc.name)) {
        const confirmed = await onToolConfirm(tc.name, tc.args);
        if (!confirmed) {
          console.log(renderToolResult(tc.name, 'Skipped by user', false));
          continue;
        }
      }

      // Execute tool
      const spinner = ora({
        text: colors.dim(`Running ${tc.name}...`),
        spinner: 'dots',
        color: 'cyan',
      }).start();

      try {
        const result = await executeTool(tc.name, tc.args);
        spinner.stop();

        // Track context
        if (tc.name === 'read_file' && tc.args.path) {
          session.addToContext(tc.args.path);
        }

        console.log(renderToolResult(tc.name, result, true));

        // For edit_file, show diff
        if (tc.name === 'edit_file' && tc.args.old_text && tc.args.new_text) {
          console.log(renderDiff(tc.args.path, tc.args.old_text, tc.args.new_text));
        }

        // Feed result back for continuation
        session.addMessage('assistant', fullResponse);
        session.addMessage('user', `[Tool result for ${tc.name}]: ${truncateForContext(result)}`);

        // Get follow-up response
        const followUp = await streamCompletion(config, systemPrompt, session.getApiMessages());
        const { text: followText, toolCalls: moreTools } = parseResponse(followUp);

        if (followText.trim()) {
          renderResponseLine('');
          renderResponseLine(followText.trim());
        }

        if (moreTools.length > 0) {
          // Recursive tool handling (max depth handled by API token limits)
          for (const ftc of moreTools) {
            console.log(renderToolCall(ftc.name, ftc.args));

            if (needsConfirmation(ftc.name)) {
              const conf = await onToolConfirm(ftc.name, ftc.args);
              if (!conf) {
                console.log(renderToolResult(ftc.name, 'Skipped by user', false));
                continue;
              }
            }

            const fSpinner = ora({
              text: colors.dim(`Running ${ftc.name}...`),
              spinner: 'dots',
              color: 'cyan',
            }).start();

            try {
              const fResult = await executeTool(ftc.name, ftc.args);
              fSpinner.stop();
              console.log(renderToolResult(ftc.name, fResult, true));

              if (ftc.name === 'read_file' && ftc.args.path) {
                session.addToContext(ftc.args.path);
              }
            } catch (fErr) {
              fSpinner.fail(colors.error(fErr.message));
              console.log(renderToolResult(ftc.name, fErr.message, false));
            }
          }

          session.addMessage('assistant', followUp);
        } else {
          session.addMessage('assistant', followUp);
        }
      } catch (err) {
        spinner.fail(colors.error(err.message));
        console.log(renderToolResult(tc.name, err.message, false));
      }
    }
  } else {
    session.addMessage('assistant', fullResponse);
  }

  // response done
  session.save();
}

/**
 * Stream a completion from the Anthropic API
 */
function streamCompletion(config, systemPrompt, messages) {
  return new Promise((resolve, reject) => {
    if (!config.apiKey) {
      reject(new Error('No API key configured. Set MAGI_API_KEY environment variable.'));
      return;
    }

    const url = new URL(config.apiUrl);

    const apiMessages = [
      { role: 'system', content: systemPrompt },
      ...messages.map(m => ({ role: m.role, content: m.content }))
    ];
    const body = JSON.stringify({
      model: config.model,
      max_tokens: 4096,
      messages: apiMessages,
      stream: true,
    });

    const options = {
      hostname: url.hostname,
      port: url.port || (url.protocol === 'https:' ? 443 : 80),
      path: url.pathname,
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': 'Bearer ' + config.apiKey,
        'Content-Length': Buffer.byteLength(body),
      },
    };

    const transport = url.protocol === 'https:' ? https : http;

    const req = transport.request(options, (res) => {
      if (res.statusCode !== 200) {
        let errorBody = '';
        res.on('data', (chunk) => { errorBody += chunk; });
        res.on('end', () => {
          try {
            const err = JSON.parse(errorBody);
            reject(new Error(err.error?.message || `API returned ${res.statusCode}`));
          } catch {
            reject(new Error(`API returned ${res.statusCode}: ${errorBody.slice(0, 200)}`));
          }
        });
        return;
      }

      let fullText = '';
      let buffer = '';

      res.on('data', (chunk) => {
        buffer += chunk.toString();

        // Process SSE events
        const lines = buffer.split('\n');
        buffer = lines.pop() || ''; // Keep incomplete line

        for (const line of lines) {
          if (line.startsWith('data: ')) {
            const data = line.slice(6).trim();
            if (data === '[DONE]') continue;

            try {
              const event = JSON.parse(data);

              // OpenAI format
              const delta = event.choices?.[0]?.delta;
              if (delta?.content) {
                fullText += delta.content;
                // Show streaming char-by-char (clean, no box borders during stream)
                process.stdout.write(delta.content);
              }
            } catch {
              // Skip malformed events
            }
          }
        }
      });

      res.on('end', () => {
        process.stdout.write('\n');
        resolve(fullText);
      });

      res.on('error', reject);
    });

    req.on('error', (err) => {
      if (err.code === 'ECONNREFUSED') {
        reject(new Error(`Cannot connect to API at ${config.apiUrl}`));
      } else {
        reject(err);
      }
    });

    req.write(body);
    req.end();
  });
}

/**
 * Parse tool calls from response text
 * Format: <tool_call name="tool_name"><param name="key">value</param></tool_call>
 */
function parseResponse(responseText) {
  const toolCalls = [];
  let text = responseText;

  const toolCallRegex = /<tool_call\s+name="([^"]+)">([\s\S]*?)<\/tool_call>/g;
  let match;

  while ((match = toolCallRegex.exec(responseText)) !== null) {
    const toolName = match[1];
    const paramsStr = match[2];
    const args = {};

    const paramRegex = /<param\s+name="([^"]+)">([\s\S]*?)<\/param>/g;
    let paramMatch;

    while ((paramMatch = paramRegex.exec(paramsStr)) !== null) {
      args[paramMatch[1]] = paramMatch[2];
    }

    toolCalls.push({ name: toolName, args });

    // Remove tool call from display text
    text = text.replace(match[0], '');
  }

  // Also remove <reason> tags from display
  text = text.replace(/<reason>[\s\S]*?<\/reason>/g, '');

  return { text: text.trim(), toolCalls };
}

function truncateForContext(text) {
  const maxLen = 2000;
  if (text.length <= maxLen) return text;
  return text.slice(0, maxLen) + `\n...[truncated, ${text.length - maxLen} chars omitted]`;
}

/**
 * MAGI Code — Configuration
 */
import fs from 'fs';
import path from 'path';
import os from 'os';
import { execSync } from 'child_process';

const DEFAULT_API_URL = process.env.MAGI_API_URL || 'http://127.0.0.1:3005/v1/chat/completions';
const DEFAULT_MODEL = 'magi-auto';

const PROJECT_MARKERS = [
  'package.json', 'Cargo.toml', 'pyproject.toml', 'go.mod',
  'Gemfile', 'pom.xml', 'build.gradle', 'CMakeLists.txt',
  'Makefile', '.git', 'requirements.txt', 'setup.py',
  'tsconfig.json', 'deno.json', 'composer.json'
];

const DEFAULT_IGNORE = [
  'node_modules', '.git', '.magi', 'dist', 'build', '.next',
  '__pycache__', '.venv', 'venv', 'target', '.DS_Store',
  '*.lock', 'package-lock.json', 'yarn.lock', 'pnpm-lock.yaml',
  '.env', '.env.*', 'coverage', '.nyc_output', '.cache'
];

const AGENTS = {
  rafael: { name: 'Rafael', emoji: '🧭', role: 'The Architect', color: '#FF6B35' },
  uriel:  { name: 'Uriel',  emoji: '🔥', role: 'The Validator', color: '#FF4444' },
  michael:{ name: 'Michael',emoji: '🛡️', role: 'The Wise Advisor', color: '#4A90D9' },
  gabriel:{ name: 'Gabriel',emoji: '📣', role: 'The Voice', color: '#FFD700' },
  raguel: { name: 'Raguel', emoji: '🤝', role: 'The Friend', color: '#50C878' },
  magi:   { name: 'MAGI',   emoji: '🐱', role: 'Coding Agent', color: '#C084FC' },
};

export function loadConfig() {
  const projectDir = findProjectRoot(process.cwd());
  const magiDir = path.join(projectDir, '.magi');
  const configPath = path.join(magiDir, 'config.json');
  const globalConfigPath = path.join(os.homedir(), '.magi', 'config.json');

  // Ensure .magi directory exists
  if (!fs.existsSync(magiDir)) {
    fs.mkdirSync(magiDir, { recursive: true });
  }
  if (!fs.existsSync(path.join(magiDir, 'sessions'))) {
    fs.mkdirSync(path.join(magiDir, 'sessions'), { recursive: true });
  }

  let fileConfig = {};
  // Try local config first, then global
  for (const cfgPath of [configPath, globalConfigPath]) {
    if (fs.existsSync(cfgPath)) {
      try {
        fileConfig = JSON.parse(fs.readFileSync(cfgPath, 'utf-8'));
        break;
      } catch { /* ignore bad config */ }
    }
  }

  const config = {
    apiUrl: process.env.MAGI_API_URL || fileConfig.apiUrl || DEFAULT_API_URL,
    apiKey: process.env.MAGI_API_KEY || process.env.MAGI_API_KEY || fileConfig.apiKey || '',
    model: process.env.MAGI_MODEL || fileConfig.model || DEFAULT_MODEL,
    agent: fileConfig.agent || 'magi',
    projectDir,
    magiDir,
    userName: (() => { try { return execSync('git config user.name', {encoding:'utf8'}).trim() || process.env.USER || 'User'; } catch { return process.env.USER || 'User'; } })(),
    projectType: detectProjectType(projectDir),
    ignorePatterns: loadIgnorePatterns(projectDir),
    agents: AGENTS,
    maxContextTokens: 100000,
  };

  return config;
}

function findProjectRoot(dir) {
  let current = dir;
  while (current !== path.dirname(current)) {
    for (const marker of PROJECT_MARKERS) {
      if (fs.existsSync(path.join(current, marker))) {
        return current;
      }
    }
    current = path.dirname(current);
  }
  return dir; // fallback to cwd
}

function detectProjectType(dir) {
  const checks = [
    ['package.json', 'node'],
    ['Cargo.toml', 'rust'],
    ['pyproject.toml', 'python'],
    ['go.mod', 'go'],
    ['Gemfile', 'ruby'],
    ['pom.xml', 'java'],
    ['build.gradle', 'java'],
    ['CMakeLists.txt', 'cpp'],
    ['tsconfig.json', 'typescript'],
    ['deno.json', 'deno'],
    ['composer.json', 'php'],
    ['requirements.txt', 'python'],
    ['setup.py', 'python'],
  ];
  for (const [file, type] of checks) {
    if (fs.existsSync(path.join(dir, file))) return type;
  }
  return 'unknown';
}

function loadIgnorePatterns(dir) {
  const patterns = [...DEFAULT_IGNORE];

  // Load .gitignore
  const gitignore = path.join(dir, '.gitignore');
  if (fs.existsSync(gitignore)) {
    const lines = fs.readFileSync(gitignore, 'utf-8').split('\n');
    for (const line of lines) {
      const trimmed = line.trim();
      if (trimmed && !trimmed.startsWith('#')) {
        patterns.push(trimmed);
      }
    }
  }

  // Load .magiignore
  const magiignore = path.join(dir, '.magiignore');
  if (fs.existsSync(magiignore)) {
    const lines = fs.readFileSync(magiignore, 'utf-8').split('\n');
    for (const line of lines) {
      const trimmed = line.trim();
      if (trimmed && !trimmed.startsWith('#')) {
        patterns.push(trimmed);
      }
    }
  }

  return [...new Set(patterns)];
}

export function getSystemPrompt(config) {
  const agentInfo = config.agents[config.agent] || config.agents.magi;
  return `You are ${agentInfo.name} (${agentInfo.emoji} ${agentInfo.role}), an AI coding agent running in the user's terminal via MAGI Code. You have access to their codebase and can read files, edit code, run commands, and search the project.

Project: ${config.projectDir}
Project type: ${config.projectType}

Available tools (use XML format):
<tool_call name="read_file"><param name="path">filepath</param></tool_call>
<tool_call name="write_file"><param name="path">filepath</param><param name="content">file content</param></tool_call>
<tool_call name="edit_file"><param name="path">filepath</param><param name="old_text">text to find</param><param name="new_text">replacement text</param></tool_call>
<tool_call name="run_command"><param name="command">shell command</param></tool_call>
<tool_call name="search_files"><param name="query">search term</param><param name="path">optional directory</param></tool_call>
<tool_call name="list_files"><param name="path">directory path</param></tool_call>

Rules:
- Always read files before editing them
- Show reasoning before changes
- Ask confirmation before destructive actions
- Use edit_file for surgical changes, write_file for new files
- CAVEMAN MODE: Drop articles, filler, pleasantries. Short synonyms. No hedging. Fragments OK. Technical terms exact. Code blocks unchanged. Be concise — few words, full substance.
- When showing code changes, explain what and why — briefly`;
}

/**
 * MAGI Code — Codebase Context Builder
 */
import fs from 'fs';
import path from 'path';

export class ContextBuilder {
  constructor(projectDir, ignorePatterns) {
    this.projectDir = projectDir;
    this.ignorePatterns = ignorePatterns || [];
    this.fileTree = null;
  }

  /**
   * Build a file tree of the project
   */
  buildFileTree(maxDepth = 4) {
    this.fileTree = this._walkDir(this.projectDir, 0, maxDepth);
    return this.fileTree;
  }

  /**
   * Get a string representation of the file tree
   */
  getFileTreeString(maxDepth = 3) {
    const tree = this.buildFileTree(maxDepth);
    return this._renderTree(tree, '', true);
  }

  /**
   * Generate a codebase summary for the system prompt
   */
  generateSummary() {
    const treeStr = this.getFileTreeString(3);
    const projectName = path.basename(this.projectDir);

    const lines = [
      `Project: ${projectName}`,
      `Root: ${this.projectDir}`,
      '',
      'File structure:',
      treeStr,
    ];

    // Check for specific config files and add context
    const configs = this._detectConfigs();
    if (configs.length > 0) {
      lines.push('');
      lines.push('Project configuration:');
      for (const config of configs) {
        lines.push(`- ${config}`);
      }
    }

    return lines.join('\n');
  }

  /**
   * Estimate token count for a string (~4 chars per token)
   */
  estimateTokens(text) {
    return Math.ceil(text.length / 4);
  }

  // ─── Private Methods ────────────────────────────────────────
  _walkDir(dir, depth, maxDepth) {
    if (depth >= maxDepth) return null;

    const node = {
      name: path.basename(dir),
      type: 'directory',
      children: [],
    };

    let entries;
    try {
      entries = fs.readdirSync(dir, { withFileTypes: true });
    } catch {
      return node;
    }

    // Sort: directories first, then files
    entries.sort((a, b) => {
      if (a.isDirectory() && !b.isDirectory()) return -1;
      if (!a.isDirectory() && b.isDirectory()) return 1;
      return a.name.localeCompare(b.name);
    });

    for (const entry of entries) {
      if (this._shouldIgnore(entry.name)) continue;

      if (entry.isDirectory()) {
        const child = this._walkDir(path.join(dir, entry.name), depth + 1, maxDepth);
        if (child) node.children.push(child);
      } else if (entry.isFile()) {
        node.children.push({
          name: entry.name,
          type: 'file',
        });
      }
    }

    return node;
  }

  _renderTree(node, prefix, isLast) {
    if (!node) return '';

    const lines = [];
    const connector = isLast ? '└── ' : '├── ';
    const icon = node.type === 'directory' ? '📁 ' : '📄 ';

    if (prefix !== undefined && prefix !== null) {
      lines.push(prefix + connector + icon + node.name);
    }

    if (node.children) {
      const childPrefix = prefix + (isLast ? '    ' : '│   ');
      for (let i = 0; i < node.children.length; i++) {
        const child = node.children[i];
        const childIsLast = i === node.children.length - 1;
        lines.push(this._renderTree(child, childPrefix, childIsLast));
      }
    }

    return lines.filter(Boolean).join('\n');
  }

  _shouldIgnore(name) {
    if (name.startsWith('.')) return true;

    for (const pattern of this.ignorePatterns) {
      // Simple glob matching
      if (pattern === name) return true;
      if (pattern.startsWith('*') && name.endsWith(pattern.slice(1))) return true;
      if (pattern.endsWith('*') && name.startsWith(pattern.slice(0, -1))) return true;
      if (pattern.endsWith('/') && name === pattern.slice(0, -1)) return true;
    }

    return false;
  }

  _detectConfigs() {
    const configs = [];
    const checks = [
      ['package.json', () => {
        try {
          const pkg = JSON.parse(fs.readFileSync(path.join(this.projectDir, 'package.json'), 'utf-8'));
          return `Node.js project: ${pkg.name || 'unnamed'} v${pkg.version || '0.0.0'}`;
        } catch { return 'Node.js project'; }
      }],
      ['tsconfig.json', () => 'TypeScript configured'],
      ['Cargo.toml', () => 'Rust project'],
      ['pyproject.toml', () => 'Python project'],
      ['go.mod', () => 'Go project'],
      ['.env.example', () => 'Environment variables configured'],
      ['docker-compose.yml', () => 'Docker Compose configured'],
      ['Dockerfile', () => 'Docker configured'],
    ];

    for (const [file, describe] of checks) {
      if (fs.existsSync(path.join(this.projectDir, file))) {
        configs.push(describe());
      }
    }

    return configs;
  }
}

#!/usr/bin/env node
/**
 * ╔══════════════════════════════════════════╗
 * ║  MAGI Code — AI Coding Agent            ║
 * ║  Terminal UI inspired by Claude Code     ║
 * ║  With a cat mascot, because why not      ║
 * ╚══════════════════════════════════════════╝
 */
import readline from 'readline';
import { loadConfig } from './config.js';
import { SessionManager } from './session.js';
import { ContextBuilder } from './context.js';
import { sendMessage } from './agent.js';
import { performUndo } from './tools.js';
import {
  renderWelcome, renderHelp, renderAgentList,
  renderContext, renderError, getPromptString,
  colors, stripAnsi,
} from './ui.js';

// ─── Globals ─────────────────────────────────────────────────
let config;
let session;
let context;
let rl;
let isProcessing = false;
let commandHistory = [];
let historyIndex = -1;

// ─── Parse CLI Args ──────────────────────────────────────────
function parseArgs() {
  const args = process.argv.slice(2);
  const opts = { agent: null, resume: false };

  for (let i = 0; i < args.length; i++) {
    switch (args[i]) {
      case '--version':
      case '-v':
        console.log('magi-code v1.0.0');
        process.exit(0);
        break;
      case '--help':
      case '-h':
        printUsage();
        process.exit(0);
        break;
      case '--agent':
      case '-a':
        opts.agent = args[++i];
        break;
      case '--resume':
      case '-r':
        opts.resume = true;
        break;
    }
  }

  return opts;
}

function printUsage() {
  console.log(`
  ${colors.primary('MAGI Code')} — AI coding agent ${colors.dim('v1.0.0')}

  ${colors.bold('Usage:')} magi [options]

  ${colors.bold('Options:')}
    --agent, -a <name>   Start with a specific agent
    --resume, -r         Resume last session
    --version, -v        Show version
    --help, -h           Show this help

  ${colors.bold('Commands (inside MAGI):')}
    /help                Show all commands
    /agents              List available agents
    /agent <name>        Switch agent
    /exit                Quit

  ${colors.bold('Environment:')}
    MAGI_API_KEY    Your Anthropic API key
    MAGI_MODEL           Model to use (default: magi-auto)
    MAGI_API_URL         Custom API endpoint
`);
}

// ─── Input Loop ──────────────────────────────────────────────
function startInputLoop() {
  rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout,
    prompt: getPromptString(),
    historySize: 100,
    terminal: true,
  });

  rl.prompt();

  rl.on('line', async (line) => {
    const input = line.trim();

    if (!input) {
      rl.prompt();
      return;
    }

    // Save to history
    commandHistory.push(input);
    historyIndex = commandHistory.length;

    if (input.startsWith('/')) {
      await handleCommand(input);
    } else {
      await handleMessage(input);
    }
  });

  rl.on('close', () => {
    console.log(colors.dim('\n  Goodbye! 🐱\n'));
    if (session) session.save();
    process.exit(0);
  });

  // Handle Ctrl+C during processing
  rl.on('SIGINT', () => {
    if (isProcessing) {
      isProcessing = false;
      console.log(colors.warning('\n  Cancelled.'));
      rl.prompt();
    } else {
      console.log(colors.dim('\n  Press Ctrl+D to exit, or type /exit'));
      rl.prompt();
    }
  });
}

// ─── Command Handler ─────────────────────────────────────────
async function handleCommand(input) {
  const parts = input.split(/\s+/);
  const cmd = parts[0].toLowerCase();
  const args = parts.slice(1).join(' ');

  switch (cmd) {
    case '/help':
      renderHelp();
      break;

    case '/agent':
      if (!args) {
        console.log(colors.warning('  Usage: /agent <name>'));
        console.log(colors.dim('  Use /agents to see available agents'));
      } else {
        const agentId = args.toLowerCase();
        if (config.agents[agentId]) {
          config.agent = agentId;
          const a = config.agents[agentId];
          console.log(colors.success(`\n  Switched to ${a.emoji} ${a.name} — ${a.role}\n`));
        } else {
          console.log(colors.error(`  Unknown agent: ${args}`));
          console.log(colors.dim('  Use /agents to see available agents'));
        }
      }
      break;

    case '/agents':
      renderAgentList(config.agents, config.agent);
      break;

    case '/panel':
      if (!args) {
        console.log(colors.warning('  Usage: /panel <question>'));
      } else {
        console.log(colors.dim('\n  Panel mode — consulting multiple agents...\n'));
        // Send to current agent for now
        await handleMessage(`[Panel Discussion] ${args}`);
        return; // handleMessage does its own prompt
      }
      break;

    case '/context':
      renderContext(session.getContextFiles(), session.estimateTokens());
      break;

    case '/undo': {
      const result = performUndo();
      if (result) {
        console.log(colors.success(`\n  Undo: ${result.path} — ${result.action}\n`));
      } else {
        console.log(colors.warning('\n  Nothing to undo.\n'));
      }
      break;
    }

    case '/clear': {
      const count = session.clear();
      console.log(colors.success(`\n  Cleared ${count} messages.\n`));
      break;
    }

    case '/compact': {
      const compacted = session.compact();
      if (compacted > 0) {
        console.log(colors.success(`\n  Compacted ${compacted} messages.\n`));
      } else {
        console.log(colors.dim('\n  Not enough messages to compact.\n'));
      }
      break;
    }

    case '/resume': {
      const resumed = session.resume();
      if (resumed) {
        console.log(colors.success(`\n  Resumed session from ${resumed.startedAt}\n`));
        console.log(colors.dim(`  ${session.messages.length} messages loaded, ${session.getContextFiles().length} files in context\n`));
      } else {
        console.log(colors.warning('\n  No previous session found.\n'));
      }
      break;
    }

    case '/exit':
      session.save();
      console.log(colors.dim('\n  Goodbye! 🐱\n'));
      process.exit(0);
      break;

    default:
      console.log(colors.warning(`  Unknown command: ${cmd}`));
      console.log(colors.dim('  Type /help for available commands'));
  }

  rl.prompt();
}

// ─── Message Handler ─────────────────────────────────────────
async function handleMessage(input) {
  isProcessing = true;
  console.log(); // Spacing

  try {
    await sendMessage(config, session, input, {
      onToolConfirm: async (toolName, args) => {
        return new Promise((resolve) => {
          const summary = toolName === 'run_command' 
            ? `Execute: ${args.command}`
            : toolName === 'write_file'
            ? `Write to: ${args.path}`
            : toolName === 'edit_file'
            ? `Edit: ${args.path}`
            : `${toolName}`;

          rl.question(
            colors.warning(`  Allow ${summary}? `) + colors.dim('[Y/n] '),
            (answer) => {
              const a = answer.trim().toLowerCase();
              resolve(a === '' || a === 'y' || a === 'yes');
            }
          );
        });
      },
    });
  } catch (err) {
    renderError(err.message);
  }

  isProcessing = false;
  console.log();
  rl.prompt();
}

// ─── Main ────────────────────────────────────────────────────
async function main() {
  const opts = parseArgs();

  // Load configuration
  config = loadConfig();

  // Override agent from CLI
  if (opts.agent) {
    const agentId = opts.agent.toLowerCase();
    if (config.agents[agentId]) {
      config.agent = agentId;
    } else {
      console.log(colors.warning(`Unknown agent: ${opts.agent}, using default`));
    }
  }

  // Initialize session
  session = new SessionManager(config.magiDir);

  if (opts.resume) {
    const resumed = session.resume();
    if (!resumed) {
      session.newSession();
    }
  } else {
    session.newSession();
  }

  // Initialize context builder
  context = new ContextBuilder(config.projectDir, config.ignorePatterns);

  // Check for API key
  if (!config.apiKey) {
    renderWelcome(config);
    console.log(colors.warning('  ⚠️  No API key found!'));
    console.log(colors.dim('  Set it with: export MAGI_API_KEY=sk-ant-...\n'));
    console.log(colors.dim('  Or create ~/.magi/config.json with: { "apiKey": "sk-ant-..." }\n'));
  } else {
    renderWelcome(config);
  }

  // Start interactive loop
  startInputLoop();
}

// ─── Run ─────────────────────────────────────────────────────
main().catch((err) => {
  console.error(colors.error(`Fatal: ${err.message}`));
  process.exit(1);
});

/**
 * MAGI Code — Session Management
 */
import fs from 'fs';
import path from 'path';
import crypto from 'crypto';

export class SessionManager {
  constructor(magiDir) {
    this.magiDir = magiDir;
    this.sessionsDir = path.join(magiDir, 'sessions');
    this.currentSession = null;
    this.messages = [];
    this.contextFiles = new Set();
    this.messageCount = 0;
    this.autoSaveInterval = 5;

    if (!fs.existsSync(this.sessionsDir)) {
      fs.mkdirSync(this.sessionsDir, { recursive: true });
    }
  }

  /**
   * Start a new session
   */
  newSession() {
    this.currentSession = {
      id: crypto.randomUUID(),
      startedAt: new Date().toISOString(),
      lastActivity: new Date().toISOString(),
    };
    this.messages = [];
    this.contextFiles = new Set();
    this.messageCount = 0;
    this.save();
    return this.currentSession;
  }

  /**
   * Resume the most recent session
   */
  resume() {
    const sessions = this.listSessions();
    if (sessions.length === 0) return null;

    const latest = sessions[0];
    return this.loadSession(latest.id);
  }

  /**
   * Load a specific session
   */
  loadSession(sessionId) {
    const sessionPath = path.join(this.sessionsDir, `${sessionId}.json`);
    if (!fs.existsSync(sessionPath)) return null;

    try {
      const data = JSON.parse(fs.readFileSync(sessionPath, 'utf-8'));
      this.currentSession = data.session;
      this.messages = data.messages || [];
      this.contextFiles = new Set(data.contextFiles || []);
      this.messageCount = this.messages.length;
      return this.currentSession;
    } catch {
      return null;
    }
  }

  /**
   * List all sessions (most recent first)
   */
  listSessions() {
    if (!fs.existsSync(this.sessionsDir)) return [];

    const files = fs.readdirSync(this.sessionsDir)
      .filter(f => f.endsWith('.json'))
      .map(f => {
        try {
          const data = JSON.parse(fs.readFileSync(path.join(this.sessionsDir, f), 'utf-8'));
          return {
            id: data.session.id,
            startedAt: data.session.startedAt,
            lastActivity: data.session.lastActivity,
            messageCount: (data.messages || []).length,
          };
        } catch {
          return null;
        }
      })
      .filter(Boolean)
      .sort((a, b) => new Date(b.lastActivity) - new Date(a.lastActivity));

    return files;
  }

  /**
   * Get recent activity for welcome screen
   */
  getRecentActivity(limit = 4) {
    const sessions = this.listSessions();
    return sessions.slice(0, limit).map(s => {
      const ago = timeAgo(new Date(s.lastActivity));
      return { ago, messageCount: s.messageCount, id: s.id };
    });
  }

  /**
   * Add a message to the session
   */
  addMessage(role, content) {
    this.messages.push({
      role,
      content,
      timestamp: new Date().toISOString(),
    });
    this.messageCount++;

    if (this.currentSession) {
      this.currentSession.lastActivity = new Date().toISOString();
    }

    // Auto-save periodically
    if (this.messageCount % this.autoSaveInterval === 0) {
      this.save();
    }
  }

  /**
   * Add a file to context tracking
   */
  addToContext(filePath) {
    this.contextFiles.add(filePath);
  }

  /**
   * Get context files list
   */
  getContextFiles() {
    return [...this.contextFiles];
  }

  /**
   * Estimate token count (rough: ~4 chars per token)
   */
  estimateTokens() {
    const totalChars = this.messages.reduce((sum, m) => sum + (m.content || '').length, 0);
    return Math.ceil(totalChars / 4);
  }

  /**
   * Get messages formatted for API
   */
  getApiMessages() {
    return this.messages.map(m => ({
      role: m.role,
      content: m.content,
    }));
  }

  /**
   * Compact old messages (summarize)
   */
  compact() {
    if (this.messages.length < 10) return 0;

    const keep = 6; // Keep last N messages
    const toCompact = this.messages.slice(0, -keep);
    const kept = this.messages.slice(-keep);

    const summary = `[Session summary: ${toCompact.length} messages compacted. ` +
      `Topics discussed: ${extractTopics(toCompact)}]`;

    this.messages = [
      { role: 'assistant', content: summary, timestamp: new Date().toISOString() },
      ...kept,
    ];

    this.save();
    return toCompact.length;
  }

  /**
   * Clear all messages
   */
  clear() {
    const count = this.messages.length;
    this.messages = [];
    this.contextFiles = new Set();
    this.messageCount = 0;
    this.save();
    return count;
  }

  /**
   * Save current session to disk
   */
  save() {
    if (!this.currentSession) return;

    const sessionPath = path.join(this.sessionsDir, `${this.currentSession.id}.json`);
    const data = {
      session: this.currentSession,
      messages: this.messages,
      contextFiles: [...this.contextFiles],
    };

    fs.writeFileSync(sessionPath, JSON.stringify(data, null, 2), 'utf-8');
  }
}

// ─── Helpers ─────────────────────────────────────────────────
function timeAgo(date) {
  const seconds = Math.floor((Date.now() - date.getTime()) / 1000);
  if (seconds < 60) return 'just now';
  if (seconds < 3600) return `${Math.floor(seconds / 60)}m ago`;
  if (seconds < 86400) return `${Math.floor(seconds / 3600)}h ago`;
  if (seconds < 604800) return `${Math.floor(seconds / 86400)}d ago`;
  return `${Math.floor(seconds / 604800)}w ago`;
}

function extractTopics(messages) {
  const userMessages = messages
    .filter(m => m.role === 'user')
    .map(m => m.content)
    .join(' ');

  // Very basic topic extraction
  const words = userMessages.split(/\s+/)
    .filter(w => w.length > 4)
    .reduce((acc, w) => { acc[w] = (acc[w] || 0) + 1; return acc; }, {});

  return Object.entries(words)
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(([w]) => w)
    .join(', ') || 'general discussion';
}

/**
 * MAGI Code — Tool Implementations
 */
import fs from 'fs';
import path from 'path';
import { execSync, spawn } from 'child_process';

// Undo stack for file operations
const undoStack = [];

export function getUndoStack() {
  return undoStack;
}

const TOOLS = {
  read_file: {
    description: 'Read the contents of a file',
    params: ['path'],
    needsConfirm: false,
    execute: async ({ path: filePath }) => {
      const resolved = resolvePath(filePath);
      if (!fs.existsSync(resolved)) {
        throw new Error(`File not found: ${filePath}`);
      }
      const stat = fs.statSync(resolved);
      if (stat.size > 1024 * 1024) {
        throw new Error(`File too large (${(stat.size / 1024 / 1024).toFixed(1)}MB). Max 1MB.`);
      }
      return fs.readFileSync(resolved, 'utf-8');
    },
  },

  write_file: {
    description: 'Create or overwrite a file with new content',
    params: ['path', 'content'],
    needsConfirm: true,
    execute: async ({ path: filePath, content }) => {
      const resolved = resolvePath(filePath);
      const dir = path.dirname(resolved);
      if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true });
      }

      // Save for undo
      const existed = fs.existsSync(resolved);
      const oldContent = existed ? fs.readFileSync(resolved, 'utf-8') : null;
      undoStack.push({
        type: 'write_file',
        path: resolved,
        oldContent,
        existed,
        timestamp: Date.now(),
      });

      fs.writeFileSync(resolved, content, 'utf-8');
      return `Wrote ${content.length} bytes to ${filePath}`;
    },
  },

  edit_file: {
    description: 'Edit a file by replacing specific text',
    params: ['path', 'old_text', 'new_text'],
    needsConfirm: true,
    execute: async ({ path: filePath, old_text, new_text }) => {
      const resolved = resolvePath(filePath);
      if (!fs.existsSync(resolved)) {
        throw new Error(`File not found: ${filePath}`);
      }

      const content = fs.readFileSync(resolved, 'utf-8');
      if (!content.includes(old_text)) {
        throw new Error(`Could not find the specified text in ${filePath}`);
      }

      // Save for undo
      undoStack.push({
        type: 'edit_file',
        path: resolved,
        oldContent: content,
        existed: true,
        timestamp: Date.now(),
      });

      const newContent = content.replace(old_text, new_text);
      fs.writeFileSync(resolved, newContent, 'utf-8');

      const oldLines = old_text.split('\n').length;
      const newLines = new_text.split('\n').length;
      return `Edited ${filePath}: replaced ${oldLines} line(s) with ${newLines} line(s)`;
    },
  },

  run_command: {
    description: 'Execute a shell command',
    params: ['command'],
    needsConfirm: true,
    execute: async ({ command }) => {
      return new Promise((resolve, reject) => {
        const proc = spawn('bash', ['-c', command], {
          cwd: process.cwd(),
          timeout: 30000,
          maxBuffer: 1024 * 1024,
        });

        let stdout = '';
        let stderr = '';

        proc.stdout.on('data', (data) => { stdout += data.toString(); });
        proc.stderr.on('data', (data) => { stderr += data.toString(); });

        proc.on('close', (code) => {
          const output = (stdout + (stderr ? '\nSTDERR:\n' + stderr : '')).trim();
          if (code !== 0) {
            resolve(`[exit code ${code}]\n${output}`);
          } else {
            resolve(output || '(no output)');
          }
        });

        proc.on('error', (err) => {
          reject(new Error(`Command failed: ${err.message}`));
        });
      });
    },
  },

  search_files: {
    description: 'Search for text across files in the project',
    params: ['query', 'path'],
    needsConfirm: false,
    execute: async ({ query, path: searchPath }) => {
      const dir = searchPath ? resolvePath(searchPath) : process.cwd();
      try {
        const result = execSync(
          `grep -rn --include='*' -l "${query.replace(/"/g, '\\"')}" "${dir}" 2>/dev/null | head -20`,
          { timeout: 10000, encoding: 'utf-8' }
        ).trim();

        if (!result) return 'No matches found';

        // Get snippets
        const files = result.split('\n');
        const snippets = [];
        for (const file of files.slice(0, 10)) {
          try {
            const matches = execSync(
              `grep -n "${query.replace(/"/g, '\\"')}" "${file}" 2>/dev/null | head -3`,
              { timeout: 5000, encoding: 'utf-8' }
            ).trim();
            const relPath = path.relative(process.cwd(), file);
            snippets.push(`${relPath}:\n${matches}`);
          } catch { /* skip */ }
        }
        return snippets.join('\n\n') || 'No matches found';
      } catch {
        return 'No matches found';
      }
    },
  },

  list_files: {
    description: 'List files and directories',
    params: ['path'],
    needsConfirm: false,
    execute: async ({ path: dirPath }) => {
      const resolved = resolvePath(dirPath || '.');
      if (!fs.existsSync(resolved)) {
        throw new Error(`Directory not found: ${dirPath}`);
      }

      const entries = fs.readdirSync(resolved, { withFileTypes: true });
      const dirs = [];
      const files = [];

      for (const entry of entries) {
        if (entry.name.startsWith('.') && entry.name !== '.env.example') continue;
        if (entry.isDirectory()) {
          dirs.push(entry.name + '/');
        } else {
          files.push(entry.name);
        }
      }

      dirs.sort();
      files.sort();

      return [...dirs.map(d => `📁 ${d}`), ...files.map(f => `📄 ${f}`)].join('\n') || '(empty directory)';
    },
  },
};

function resolvePath(p) {
  if (path.isAbsolute(p)) return p;
  return path.resolve(process.cwd(), p);
}

export function getTool(name) {
  return TOOLS[name] || null;
}

export function getToolDefinitions() {
  return Object.entries(TOOLS).map(([name, tool]) => ({
    name,
    description: tool.description,
    params: tool.params,
    needsConfirm: !!tool.needsConfirm,
  }));
}

export async function executeTool(name, args) {
  const tool = TOOLS[name];
  if (!tool) throw new Error(`Unknown tool: ${name}`);
  return tool.execute(args);
}

export function needsConfirmation(name) {
  const tool = TOOLS[name];
  return tool ? !!tool.needsConfirm : true;
}

export function performUndo() {
  if (undoStack.length === 0) {
    return null;
  }

  const last = undoStack.pop();

  if (last.oldContent === null && !last.existed) {
    // File was newly created — delete it
    if (fs.existsSync(last.path)) {
      fs.unlinkSync(last.path);
    }
    return { path: last.path, action: 'deleted (was newly created)' };
  } else {
    // Restore old content
    fs.writeFileSync(last.path, last.oldContent, 'utf-8');
    return { path: last.path, action: 'restored to previous version' };
  }
}

export default TOOLS;

/**
 * MAGI Code — Terminal UI Rendering
 */
import chalk from 'chalk';
import boxen from 'boxen';

// ─── Cat Mascot ──────────────────────────────────────────────
const CAT_MASCOT = [
  '    ▄█▀▀▀▄   ▄▀▀▀█▄    ',
  '    █     ▀▀▀▀     █    ',
  '    █               █    ',
  '    █   ▀▀     ▀▀   █    ',
  '    █       ▼       █    ',
  '    █    ▀▀▀▀▀▀▀    █    ',
  '    ▀█▄▄▄▄▄▄▄▄▄▄▄▄█▀    ',
  '      █ █       █ █      ',
  '      ▀ ▀       ▀ ▀      ',
];

// ─── Colors ──────────────────────────────────────────────────
const colors = {
  primary: chalk.hex('#89CFF0'),    // Purple
  secondary: chalk.hex('#60A5FA'),  // Blue
  success: chalk.hex('#4ADE80'),    // Green
  warning: chalk.hex('#FBBF24'),    // Yellow
  error: chalk.hex('#F87171'),      // Red
  dim: chalk.dim,
  bold: chalk.bold,
  muted: chalk.gray,
};

// ─── Box Drawing Characters ──────────────────────────────────
const BOX = {
  tl: '╭', tr: '╮', bl: '╰', br: '╯',
  h: '─', v: '│',
  ltee: '├', rtee: '┤',
};

/**
 * Draw a bordered box with title
 */
function drawBox(content, { title = '', width = 0, borderColor = colors.dim, titleColor = colors.primary } = {}) {
  const termWidth = process.stdout.columns || 80;
  const boxWidth = width || Math.min(termWidth - 2, 72);
  const innerWidth = boxWidth - 2;

  const lines = [];

  // Top border with optional title
  if (title) {
    const titleStr = ` ${typeof titleColor === 'function' ? titleColor(title) : title} `;
    const titleLen = stripAnsi(titleStr).length;
    const remaining = innerWidth - titleLen - 1;
    lines.push(
      borderColor(BOX.tl + BOX.h) + titleStr + borderColor(BOX.h.repeat(Math.max(0, remaining)) + BOX.tr)
    );
  } else {
    lines.push(borderColor(BOX.tl + BOX.h.repeat(innerWidth) + BOX.tr));
  }

  // Content lines
  const contentLines = content.split('\n');
  for (const line of contentLines) {
    const stripped = stripAnsi(line);
    const padding = Math.max(0, innerWidth - stripped.length);
    lines.push(borderColor(BOX.v) + ' ' + line + ' '.repeat(padding > 0 ? padding - 1 : 0) + (padding > 0 ? ' ' : '') + borderColor(BOX.v));
  }

  // Bottom border
  lines.push(borderColor(BOX.bl + BOX.h.repeat(innerWidth) + BOX.br));

  return lines.join('\n');
}

/**
 * Strip ANSI escape codes for length calculation
 */
function stripAnsi(str) {
  return str.replace(/\x1B\[[0-9;]*[a-zA-Z]/g, '').replace(/\x1B\].*?\x07/g, '');
}

/**
 * Pad/truncate string to exact visible width
 */
function padTo(str, width) {
  const visible = stripAnsi(str).length;
  if (visible >= width) return str;
  return str + ' '.repeat(width - visible);
}

// ─── Welcome Screen ──────────────────────────────────────────
export function renderWelcome(config) {
  const agentInfo = config.agents[config.agent] || config.agents.magi;
  const userName = capitalize(config.userName);

  console.clear();
  console.log();

  // Centered cat mascot
  CAT_MASCOT.forEach(line => {
    console.log(colors.primary(center(line)));
  });

  console.log();
  console.log(center(chalk.bold.hex('#89CFF0')('M A G I')));
  console.log(center(colors.dim('AI Coding Agent')));
  console.log();
  console.log(center(colors.muted(`Welcome back, ${userName}`)));
  console.log(center(colors.dim(`${agentInfo.emoji} ${agentInfo.name} · ${config.projectType || 'project'}`)));
  console.log(center(colors.dim(config.projectDir)));
  console.log();
  console.log(center(colors.dim('Type a message to start · /help for commands · /exit to quit')));
  console.log();
}

function center(text) {
  const width = process.stdout.columns || 80;
  const stripped = text.replace(/\x1b\[[0-9;]*m/g, '');
  const pad = Math.max(0, Math.floor((width - stripped.length) / 2));
  return ' '.repeat(pad) + text;
}


// ─── Agent Response Box ──────────────────────────────────────
export function renderResponseStart(agentName, emoji) {
  const termWidth = process.stdout.columns || 80;
  const boxWidth = Math.min(termWidth - 4, 72);
  const title = `${emoji} ${agentName}`;
  const titleLen = stripAnsi(title).length + 2;
  const remaining = boxWidth - titleLen - 2;

  process.stdout.write(
    colors.primary(BOX.tl + BOX.h + ' ') + 
    colors.bold(title) + 
    colors.primary(' ' + BOX.h.repeat(Math.max(0, remaining)) + BOX.tr) + 
    '\n'
  );
}

export function renderResponseLine(text) {
  const termWidth = process.stdout.columns || 80;
  const boxWidth = Math.min(termWidth - 4, 72);
  const innerWidth = boxWidth - 2;

  const lines = wrapText(text, innerWidth - 2);
  for (const line of lines) {
    const padding = Math.max(0, innerWidth - stripAnsi(line).length);
    process.stdout.write(colors.primary(BOX.v) + ' ' + line + ' '.repeat(Math.max(0, padding - 1)) + (padding > 0 ? ' ' : '') + colors.primary(BOX.v) + '\n');
  }
}

export function renderResponseEnd() {
  const termWidth = process.stdout.columns || 80;
  const boxWidth = Math.min(termWidth - 4, 72);
  process.stdout.write(colors.primary(BOX.bl + BOX.h.repeat(boxWidth - 2) + BOX.br) + '\n\n');
}

// ─── Tool Call Display ───────────────────────────────────────
export function renderToolCall(toolName, args) {
  const termWidth = process.stdout.columns || 80;
  const boxWidth = Math.min(termWidth - 8, 66);
  const innerWidth = boxWidth - 2;

  let summary = '';
  if (args.path) summary = args.path;
  else if (args.command) summary = args.command;
  else if (args.query) summary = args.query;

  const title = `${toolName}${summary ? ': ' + summary : ''}`;
  const titleLen = Math.min(stripAnsi(title).length, innerWidth - 4);

  const out = [];
  out.push(
    '  ' + colors.dim(BOX.tl + BOX.h + ' ') + 
    colors.secondary(truncate(title, innerWidth - 4)) + 
    ' ' + colors.dim(BOX.h.repeat(Math.max(0, innerWidth - titleLen - 4)) + BOX.tr)
  );

  return out.join('\n');
}

export function renderToolResult(toolName, result, success = true) {
  const termWidth = process.stdout.columns || 80;
  const boxWidth = Math.min(termWidth - 8, 66);
  const innerWidth = boxWidth - 2;

  const icon = success ? colors.success('✓') : colors.error('✗');
  const preview = truncateMultiline(result, 8, innerWidth - 4);

  const lines = [];
  for (const line of preview.split('\n')) {
    const padded = padTo(line, innerWidth - 2);
    lines.push('  ' + colors.dim(BOX.v) + ' ' + padded + ' ' + colors.dim(BOX.v));
  }

  lines.push('  ' + colors.dim(BOX.bl + BOX.h.repeat(innerWidth) + BOX.br));
  lines.push('  ' + icon + colors.dim(` ${toolName} done`));

  return lines.join('\n');
}

// ─── Diff Display ────────────────────────────────────────────
export function renderDiff(filename, oldText, newText) {
  const lines = [];
  const oldLines = oldText.split('\n');
  const newLines = newText.split('\n');

  // Simple inline diff
  lines.push(colors.dim(`  --- ${filename}`));
  lines.push(colors.dim(`  +++ ${filename}`));

  for (const line of oldLines) {
    if (!newLines.includes(line)) {
      lines.push(colors.error(`  - ${line}`));
    }
  }
  for (const line of newLines) {
    if (!oldLines.includes(line)) {
      lines.push(colors.success(`  + ${line}`));
    }
  }

  return lines.join('\n');
}

// ─── Error Display ───────────────────────────────────────────
export function renderError(message) {
  console.log(
    boxen(colors.error(message), {
      padding: { left: 1, right: 1, top: 0, bottom: 0 },
      borderColor: 'red',
      borderStyle: 'round',
      title: '✗ Error',
      titleAlignment: 'left',
    })
  );
}

// ─── Help Screen ─────────────────────────────────────────────
export function renderHelp() {
  const cmds = [
    ['/help',              'Show this help'],
    ['/agent <name>',      'Switch to a different agent'],
    ['/agents',            'List all available agents'],
    ['/panel <question>',  'Ask multiple agents (roundtable)'],
    ['/context',           'Show files in current context'],
    ['/undo',              'Revert last file change'],
    ['/clear',             'Clear chat history'],
    ['/compact',           'Compress old messages'],
    ['/resume',            'Resume last session'],
    ['/exit',              'Quit MAGI Code'],
  ];

  const lines = cmds.map(([cmd, desc]) => {
    return `  ${colors.primary(padTo(cmd, 22))} ${colors.dim(desc)}`;
  });

  console.log();
  console.log(drawBox(lines.join('\n'), { title: '🐱 MAGI Code Commands', titleColor: colors.primary }));
  console.log();
  console.log(colors.dim('  Shortcuts: Ctrl+C cancel response  •  Ctrl+D exit  •  ↑↓ history'));
  console.log();
}

// ─── Agents List ─────────────────────────────────────────────
export function renderAgentList(agents, currentAgent) {
  const lines = Object.entries(agents).map(([id, a]) => {
    const marker = id === currentAgent ? colors.success(' ◉ ') : '   ';
    return `${marker}${a.emoji} ${colors.bold(padTo(a.name, 10))} ${colors.dim(a.role)}`;
  });
  console.log();
  console.log(drawBox(lines.join('\n'), { title: 'Available Agents' }));
