}

// ─── Context Display ─────────────────────────────────────────
export function renderContext(files, tokenEstimate) {
  const lines = files.map(f => `  ${colors.dim('•')} ${f}`);
  if (lines.length === 0) lines.push(colors.dim('  No files in context yet'));
