/**
 * MAGI Code — Tool Implementations
 * All tools are synchronous/simple. Confirmation handled by caller.
 */
import fs from 'fs';
import path from 'path';
import { execSync, spawnSync } from 'child_process';

// Undo stack for file operations
const undoStack = [];

/**
 * Resolve a path relative to cwd
 */
function resolvePath(p) {
  if (path.isAbsolute(p)) return p;
  return path.resolve(process.cwd(), p);
}

/**
 * Backup a file before modifying it
 */
function backupFile(filePath) {
  if (!fs.existsSync(filePath)) return;
  const backupDir = path.join(process.cwd(), '.magi', 'backups');
  if (!fs.existsSync(backupDir)) fs.mkdirSync(backupDir, { recursive: true });

  const basename = path.basename(filePath);
  const timestamp = Date.now();
  const backupPath = path.join(backupDir, `${basename}.${timestamp}.bak`);
  fs.copyFileSync(filePath, backupPath);
  return backupPath;
}

// ─── Tool definitions ────────────────────────────────────────
const TOOLS = {
  read_file: {
    description: 'Read the contents of a file',
    needsConfirm: false,
    execute({ path: filePath }) {
      const resolved = resolvePath(filePath);
      if (!fs.existsSync(resolved)) throw new Error(`File not found: ${filePath}`);
      const stat = fs.statSync(resolved);
      if (stat.size > 1024 * 1024) throw new Error(`File too large (${(stat.size / 1024 / 1024).toFixed(1)}MB). Max 1MB.`);
      return fs.readFileSync(resolved, 'utf-8');
    },
  },

  write_file: {
    description: 'Create or overwrite a file',
    needsConfirm: true,
    execute({ path: filePath, content }) {
      const resolved = resolvePath(filePath);
      const dir = path.dirname(resolved);
      if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });

      const existed = fs.existsSync(resolved);
      const oldContent = existed ? fs.readFileSync(resolved, 'utf-8') : null;

      if (existed) backupFile(resolved);

      // Push undo entry
      undoStack.push({ path: resolved, oldContent, existed, timestamp: Date.now() });

      fs.writeFileSync(resolved, content, 'utf-8');
      return `Wrote ${content.length} bytes to ${filePath}`;
    },
  },

  edit_file: {
    description: 'Edit a file by replacing specific text',
    needsConfirm: true,
    execute({ path: filePath, old_text, new_text }) {
      const resolved = resolvePath(filePath);
      if (!fs.existsSync(resolved)) throw new Error(`File not found: ${filePath}`);

      const content = fs.readFileSync(resolved, 'utf-8');
      if (!content.includes(old_text)) throw new Error(`Could not find the specified text in ${filePath}`);

      backupFile(resolved);
      undoStack.push({ path: resolved, oldContent: content, existed: true, timestamp: Date.now() });

      const newContent = content.replace(old_text, new_text);
      fs.writeFileSync(resolved, newContent, 'utf-8');

      const oldLines = old_text.split('\n').length;
      const newLines = new_text.split('\n').length;
      return `Edited ${filePath}: replaced ${oldLines} line(s) with ${newLines} line(s)`;
    },
  },

  run_command: {
    description: 'Execute a shell command',
    needsConfirm: true,
    execute({ command }) {
      try {
        const result = execSync(command, {
          cwd: process.cwd(),
          timeout: 30000,
          maxBuffer: 2 * 1024 * 1024,
          encoding: 'utf-8',
          stdio: ['pipe', 'pipe', 'pipe'],
        });
        return result.trim() || '(no output)';
      } catch (err) {
        // execSync throws on non-zero exit
        const stdout = (err.stdout || '').trim();
        const stderr = (err.stderr || '').trim();
        const output = [stdout, stderr].filter(Boolean).join('\n');
        return `[exit code ${err.status || 1}]\n${output || '(no output)'}`;
      }
    },
  },

  search_files: {
    description: 'Search for text across files',
    needsConfirm: false,
    execute({ query, path: searchPath }) {
      const dir = searchPath ? resolvePath(searchPath) : process.cwd();
      try {
        const escaped = query.replace(/"/g, '\\"');
        const result = execSync(
          `grep -rn --include='*' "${escaped}" "${dir}" 2>/dev/null | head -30`,
          { timeout: 10000, encoding: 'utf-8' }
        ).trim();
        if (!result) return 'No matches found';
        // Make paths relative
        return result.split('\n').map(line => {
          return line.replace(dir + '/', '');
        }).join('\n');
      } catch {
        return 'No matches found';
      }
    },
  },

  list_files: {
    description: 'List files and directories',
    needsConfirm: false,
    execute({ path: dirPath }) {
      const resolved = resolvePath(dirPath || '.');
      if (!fs.existsSync(resolved)) throw new Error(`Directory not found: ${dirPath}`);

      const entries = fs.readdirSync(resolved, { withFileTypes: true });
      const dirs = [];
      const files = [];

      for (const entry of entries) {
        if (entry.name.startsWith('.') && entry.name !== '.env.example') continue;
        if (['node_modules', 'dist', 'build', '.next', '__pycache__', '.venv', 'target'].includes(entry.name)) continue;
        if (entry.isDirectory()) dirs.push(entry.name + '/');
        else files.push(entry.name);
      }

      dirs.sort();
      files.sort();
      return [...dirs.map(d => `📁 ${d}`), ...files.map(f => `📄 ${f}`)].join('\n') || '(empty directory)';
    },
  },
};

// ─── Public API ──────────────────────────────────────────────
export function executeTool(name, args) {
  const tool = TOOLS[name];
  if (!tool) throw new Error(`Unknown tool: ${name}`);
  return tool.execute(args);
}

export function needsConfirmation(name) {
  const tool = TOOLS[name];
  return tool ? !!tool.needsConfirm : true;
}

export function performUndo() {
  if (undoStack.length === 0) return null;
  const last = undoStack.pop();

  if (last.oldContent === null && !last.existed) {
    if (fs.existsSync(last.path)) fs.unlinkSync(last.path);
    return { path: last.path, action: 'deleted (was newly created)' };
  } else {
    fs.writeFileSync(last.path, last.oldContent, 'utf-8');
    return { path: last.path, action: 'restored to previous version' };
  }
}

/**
 * MAGI Code — Session Management
 */
import fs from 'fs';
import path from 'path';
import crypto from 'crypto';

export class SessionManager {
  constructor(magiDir) {
    this.magiDir = magiDir;
    this.sessionsDir = path.join(magiDir, 'sessions');
    this.currentSession = null;
    this.messages = [];
    this.contextFiles = new Set();
    this.messageCount = 0;
    this.autoSaveInterval = 10;

    if (!fs.existsSync(this.sessionsDir)) {
      fs.mkdirSync(this.sessionsDir, { recursive: true });
    }
  }

  newSession() {
    this.currentSession = {
      id: crypto.randomUUID(),
      startedAt: new Date().toISOString(),
      lastActivity: new Date().toISOString(),
    };
    this.messages = [];
    this.contextFiles = new Set();
    this.messageCount = 0;
    return this.currentSession;
  }

  resume() {
    const sessions = this.listSessions();
    if (sessions.length === 0) return null;
    return this.loadSession(sessions[0].id);
  }

  loadSession(sessionId) {
    const sessionPath = path.join(this.sessionsDir, `${sessionId}.json`);
    if (!fs.existsSync(sessionPath)) return null;
    try {
      const data = JSON.parse(fs.readFileSync(sessionPath, 'utf-8'));
      this.currentSession = data.session;
      this.messages = data.messages || [];
      this.contextFiles = new Set(data.contextFiles || []);
      this.messageCount = this.messages.length;
      return this.currentSession;
    } catch { return null; }
  }

  listSessions() {
    if (!fs.existsSync(this.sessionsDir)) return [];
    return fs.readdirSync(this.sessionsDir)
      .filter(f => f.endsWith('.json'))
      .map(f => {
        try {
          const data = JSON.parse(fs.readFileSync(path.join(this.sessionsDir, f), 'utf-8'));
          return {
            id: data.session.id,
            startedAt: data.session.startedAt,
            lastActivity: data.session.lastActivity,
            messageCount: (data.messages || []).length,
          };
        } catch { return null; }
      })
      .filter(Boolean)
      .sort((a, b) => new Date(b.lastActivity) - new Date(a.lastActivity));
  }

  addMessage(role, content) {
    this.messages.push({
      role,
      content,
      timestamp: new Date().toISOString(),
    });
    this.messageCount++;
    if (this.currentSession) {
      this.currentSession.lastActivity = new Date().toISOString();
    }
    // Auto-save every N messages
    if (this.messageCount % this.autoSaveInterval === 0) {
      this.save();
    }
  }

  addToContext(filePath) {
    this.contextFiles.add(filePath);
  }

  getContextFiles() {
    return [...this.contextFiles];
  }

  estimateTokens() {
    const totalChars = this.messages.reduce((sum, m) => sum + (m.content || '').length, 0);
    return Math.ceil(totalChars / 4);
  }

  getApiMessages() {
    return this.messages.map(m => ({ role: m.role, content: m.content }));
  }

  compact() {
    if (this.messages.length < 10) return 0;
    const keep = 6;
    const toCompact = this.messages.slice(0, -keep);
    const kept = this.messages.slice(-keep);
    const summary = `[Session summary: ${toCompact.length} messages compacted.]`;
    this.messages = [
      { role: 'assistant', content: summary, timestamp: new Date().toISOString() },
      ...kept,
    ];
    this.save();
    return toCompact.length;
  }

  clear() {
    const count = this.messages.length;
    this.messages = [];
    this.contextFiles = new Set();
    this.messageCount = 0;
    this.save();
    return count;
  }

  save() {
    if (!this.currentSession) return;
    const sessionPath = path.join(this.sessionsDir, `${this.currentSession.id}.json`);
    const data = {
      session: this.currentSession,
      messages: this.messages,
      contextFiles: [...this.contextFiles],
    };
    try {
      fs.writeFileSync(sessionPath, JSON.stringify(data, null, 2), 'utf-8');
    } catch { /* swallow save errors */ }
  }
}

/**
 * MAGI Code — Codebase Context Builder
 */
import fs from 'fs';
import path from 'path';

export class ContextBuilder {
  constructor(projectDir, ignorePatterns) {
    this.projectDir = projectDir;
    this.ignorePatterns = ignorePatterns || [];
  }

  getFileTreeString(maxDepth = 3) {
    const tree = this._walkDir(this.projectDir, 0, maxDepth);
    return this._renderTree(tree, '', true);
  }

  generateSummary() {
    const treeStr = this.getFileTreeString(3);
    const projectName = path.basename(this.projectDir);
    const lines = [
      `Project: ${projectName}`,
      `Root: ${this.projectDir}`,
      '',
      'File structure:',
      treeStr,
    ];
    const configs = this._detectConfigs();
    if (configs.length > 0) {
      lines.push('', 'Project configuration:');
      for (const c of configs) lines.push(`- ${c}`);
    }
    return lines.join('\n');
  }

  _walkDir(dir, depth, maxDepth) {
    if (depth >= maxDepth) return null;
    const node = { name: path.basename(dir), type: 'directory', children: [] };
    let entries;
    try { entries = fs.readdirSync(dir, { withFileTypes: true }); }
    catch { return node; }

    entries.sort((a, b) => {
      if (a.isDirectory() && !b.isDirectory()) return -1;
      if (!a.isDirectory() && b.isDirectory()) return 1;
      return a.name.localeCompare(b.name);
    });

    for (const entry of entries) {
      if (this._shouldIgnore(entry.name)) continue;
      if (entry.isDirectory()) {
        const child = this._walkDir(path.join(dir, entry.name), depth + 1, maxDepth);
        if (child) node.children.push(child);
      } else if (entry.isFile()) {
        node.children.push({ name: entry.name, type: 'file' });
      }
    }
    return node;
  }

  _renderTree(node, prefix, isLast) {
    if (!node) return '';
    const lines = [];
    const connector = isLast ? '└── ' : '├── ';
    const icon = node.type === 'directory' ? '📁 ' : '📄 ';
    if (prefix !== undefined && prefix !== null) {
      lines.push(prefix + connector + icon + node.name);
    }
    if (node.children) {
      const childPrefix = prefix + (isLast ? '    ' : '│   ');
      for (let i = 0; i < node.children.length; i++) {
        lines.push(this._renderTree(node.children[i], childPrefix, i === node.children.length - 1));
      }
    }
    return lines.filter(Boolean).join('\n');
  }

  _shouldIgnore(name) {
    if (name.startsWith('.')) return true;
    for (const pattern of this.ignorePatterns) {
      if (pattern === name) return true;
      if (pattern.startsWith('*') && name.endsWith(pattern.slice(1))) return true;
      if (pattern.endsWith('*') && name.startsWith(pattern.slice(0, -1))) return true;
      if (pattern.endsWith('/') && name === pattern.slice(0, -1)) return true;
    }
    return false;
  }

  _detectConfigs() {
    const configs = [];
    const checks = [
      ['package.json', () => {
        try {
          const pkg = JSON.parse(fs.readFileSync(path.join(this.projectDir, 'package.json'), 'utf-8'));
          return `Node.js: ${pkg.name || 'unnamed'} v${pkg.version || '0.0.0'}`;
        } catch { return 'Node.js project'; }
      }],
      ['tsconfig.json', () => 'TypeScript configured'],
      ['Cargo.toml',    () => 'Rust project'],
      ['pyproject.toml',() => 'Python project'],
      ['go.mod',        () => 'Go project'],
      ['Dockerfile',    () => 'Docker configured'],
    ];
    for (const [file, describe] of checks) {
      if (fs.existsSync(path.join(this.projectDir, file))) configs.push(describe());
    }
    return configs;
  }
}

/**
 * MAGI Code — AI Agent Communication
 *
 * Core loop:
 *  1. Send messages to API (streaming SSE via http)
 *  2. Accumulate response text, print to terminal in real-time
 *  3. After stream ends, parse for <tool_call> XML tags
 *  4. If tool calls found:
 *     a. Display what tool is being called
 *     b. Execute tool (with confirmation for writes/exec)
 *     c. Append assistant message + tool result to messages
 *     d. Call API again → repeat from 1
 *  5. When response has no tool calls → done
 */
import http from 'http';
import https from 'https';
import { URL } from 'url';
import { getSystemPrompt } from './config.js';
import { executeTool, needsConfirmation } from './tools.js';
import {
  renderAgentHeader, writeStreamChar, renderStreamEnd,
  renderToolStart, renderToolOutput, renderToolEnd,
  renderDiff, getConfirmPrompt, renderError, colors,
} from './ui.js';

const MAX_TOOL_ROUNDS = 15; // safety cap on tool call loops

/**
 * Send a user message and handle the full agent loop.
 * Returns when the agent is done (no more tool calls).
 *
 * @param {object}   config
 * @param {object}   session  - SessionManager instance
 * @param {string}   userMessage
 * @param {object}   opts
 * @param {Function} opts.onToolConfirm - async (toolName, args) => boolean
 * @param {object}   opts.abortSignal   - { aborted: boolean } for Ctrl+C cancellation
 */
export async function sendMessage(config, session, userMessage, { onToolConfirm, abortSignal }) {
  const agentInfo = config.agents[config.agent] || config.agents.magi;

  // Add user message to session
  session.addMessage('user', userMessage);

  // Show agent header once
  renderAgentHeader(agentInfo.name, agentInfo.emoji);

  // Indentation for streaming text
  let needsIndent = true;

  const systemPrompt = getSystemPrompt(config);

  // ── Agent loop: stream → parse → execute tools → repeat ──
  for (let round = 0; round < MAX_TOOL_ROUNDS; round++) {
    if (abortSignal && abortSignal.aborted) break;

    const apiMessages = session.getApiMessages();

    // Stream the completion
    let fullResponse;
    try {
      fullResponse = await streamCompletion(config, systemPrompt, apiMessages, (char) => {
        // Real-time streaming output
        if (abortSignal && abortSignal.aborted) return;
        // Suppress tool_call XML from display
        // We accumulate everything and display non-XML text
        // For simplicity, show all chars during streaming; we'll clean up tool blocks after
        if (needsIndent) {
          process.stdout.write('  ');
          needsIndent = false;
        }
        if (char === '\n') {
          process.stdout.write('\n');
          needsIndent = true;
        } else {
          process.stdout.write(char);
        }
      });
    } catch (err) {
      renderError(`API Error: ${err.message}`);
      if (err.message.includes('API key') || err.message.includes('401')) {
        console.log(colors.warning('  Set your API key:'));
        console.log(colors.dim('  export MAGI_API_KEY=your-key-here\n'));
      }
      return;
    }

    if (abortSignal && abortSignal.aborted) {
      console.log(colors.warning('\n  (cancelled)'));
      break;
    }

    // End streaming block
    renderStreamEnd();

    // Parse tool calls from the full response
    const { text, toolCalls } = parseToolCalls(fullResponse);

    // Add assistant message to session
    session.addMessage('assistant', fullResponse);

    // No tool calls → done
    if (toolCalls.length === 0) {
      break;
    }

    // Execute each tool call
    for (const tc of toolCalls) {
      if (abortSignal && abortSignal.aborted) break;

      const summary = tc.args.path || tc.args.command || tc.args.query || '';
      renderToolStart(tc.name, summary);

      // Confirmation for destructive tools
      if (needsConfirmation(tc.name)) {
        const confirmSummary = tc.name === 'run_command'
          ? `run: ${tc.args.command}`
          : tc.name === 'write_file'
          ? `write: ${tc.args.path}`
          : tc.name === 'edit_file'
          ? `edit: ${tc.args.path}`
          : tc.name;

        const confirmed = await onToolConfirm(confirmSummary, tc.args);
        if (!confirmed) {
          renderToolEnd(false, 'Skipped by user');
          session.addMessage('user', `[Tool Result: ${tc.name}]\nUser declined to execute this tool.`);
          continue;
        }
      }

      // Show diff preview for edit_file before execution
      if (tc.name === 'edit_file' && tc.args.old_text && tc.args.new_text) {
        renderDiff(tc.args.path, tc.args.old_text, tc.args.new_text);
      }

      // Execute
      let result;
      try {
        result = executeTool(tc.name, tc.args);
        // Track context for read_file
        if (tc.name === 'read_file' && tc.args.path) {
          session.addToContext(tc.args.path);
        }
        renderToolOutput(truncateDisplay(result, 200));
        renderToolEnd(true, `${tc.name} done`);
      } catch (err) {
        result = `Error: ${err.message}`;
        renderToolEnd(false, err.message);
      }

      // Feed tool result back to the conversation
      session.addMessage('user', `[Tool Result: ${tc.name}]\n${truncateForContext(result)}`);
    }

    // Reset indent for next round's streaming
    needsIndent = true;

    // Show continuation header
    process.stdout.write('\n');
  }

  session.save();
}

/**
 * Stream an SSE chat completion using the http/https module.
 * Calls onChar(char) for each content character received.
 * Returns the full accumulated text.
 */
function streamCompletion(config, systemPrompt, messages, onChar) {
  return new Promise((resolve, reject) => {
    const url = new URL(config.apiUrl);

    const body = JSON.stringify({
      model: config.model,
      max_tokens: 4096,
      stream: true,
      messages: [
        { role: 'system', content: systemPrompt },
        ...messages,
      ],
    });

    const options = {
      hostname: url.hostname,
      port: url.port || (url.protocol === 'https:' ? 443 : 80),
      path: url.pathname + (url.search || ''),
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${config.apiKey}`,
        'Accept': 'text/event-stream',
        'Content-Length': Buffer.byteLength(body),
      },
    };

    const transport = url.protocol === 'https:' ? https : http;

    const req = transport.request(options, (res) => {
      if (res.statusCode !== 200) {
        let errorBody = '';
        res.on('data', (chunk) => { errorBody += chunk; });
        res.on('end', () => {
          try {
            const err = JSON.parse(errorBody);
            reject(new Error(err.error?.message || `API returned ${res.statusCode}`));
          } catch {
            reject(new Error(`API returned ${res.statusCode}: ${errorBody.slice(0, 300)}`));
          }
        });
        return;
      }

      let fullText = '';
      let buffer = '';

      res.on('data', (chunk) => {
        buffer += chunk.toString();

        // Process complete SSE lines
        const lines = buffer.split('\n');
        buffer = lines.pop() || ''; // keep incomplete trailing line

        for (const line of lines) {
          const trimmed = line.trim();
          if (!trimmed || trimmed.startsWith(':')) continue; // skip empty/comments

          if (trimmed.startsWith('data: ')) {
            const data = trimmed.slice(6);
            if (data === '[DONE]') continue;

            try {
              const event = JSON.parse(data);
              const content = event.choices?.[0]?.delta?.content;
              if (content) {
                fullText += content;
                // Call char-by-char callback
                for (const ch of content) {
                  onChar(ch);
                }
              }
            } catch {
              // malformed JSON line, skip
            }
          }
        }
      });

      res.on('end', () => {
        // Process any remaining buffer
        if (buffer.trim()) {
          const trimmed = buffer.trim();
          if (trimmed.startsWith('data: ') && trimmed.slice(6) !== '[DONE]') {
            try {
              const event = JSON.parse(trimmed.slice(6));
              const content = event.choices?.[0]?.delta?.content;
              if (content) {
                fullText += content;
                for (const ch of content) onChar(ch);
              }
            } catch { /* skip */ }
          }
        }
        resolve(fullText);
      });

      res.on('error', reject);
    });

    req.on('error', (err) => {
      if (err.code === 'ECONNREFUSED') {
        reject(new Error(`Cannot connect to API at ${config.apiUrl}. Is the server running?`));
      } else {
        reject(err);
      }
    });

    req.write(body);
    req.end();
  });
}

/**
 * Parse <tool_call> XML tags from response text.
 *
 * Format:
 *   <tool_call name="read_file">
 *     <param name="path">src/app.js</param>
 *   </tool_call>
 *
 * Returns { text, toolCalls[] }
 */
function parseToolCalls(responseText) {
  const toolCalls = [];
  let text = responseText;

  const toolCallRegex = /<tool_call\s+name="([^"]+)">([\s\S]*?)<\/tool_call>/g;
  let match;

  while ((match = toolCallRegex.exec(responseText)) !== null) {
    const toolName = match[1];
    const paramsStr = match[2];
    const args = {};

    const paramRegex = /<param\s+name="([^"]+)">([\s\S]*?)<\/param>/g;
    let paramMatch;
    while ((paramMatch = paramRegex.exec(paramsStr)) !== null) {
      args[paramMatch[1]] = paramMatch[2].trim();
    }

    toolCalls.push({ name: toolName, args });
    // Remove tool call XML from display text
    text = text.replace(match[0], '');
  }

  // Also strip <reason> tags
  text = text.replace(/<reason>[\s\S]*?<\/reason>/g, '');

  return { text: text.trim(), toolCalls };
}

/**
 * Truncate text for sending back as tool result context
 */
function truncateForContext(text) {
  const maxLen = 3000;
  if (!text || text.length <= maxLen) return text || '';
  return text.slice(0, maxLen) + `\n...[truncated, ${text.length - maxLen} chars omitted]`;
}

/**
 * Truncate text for display in terminal
 */
function truncateDisplay(text, maxLines = 200) {
  if (!text) return '';
  const lines = text.split('\n');
  if (lines.length <= maxLines) return text;
  return lines.slice(0, maxLines).join('\n') + `\n... (${lines.length - maxLines} more lines)`;
}

#!/usr/bin/env node
/**
 * MAGI Code — AI Coding Agent
 * Terminal UI inspired by Gemini CLI
 */
import readline from 'readline';
import { loadConfig } from './config.js';
import { SessionManager } from './session.js';
import { ContextBuilder } from './context.js';
import { sendMessage } from './agent.js';
import { performUndo } from './tools.js';
import {
  renderWelcome, renderHelp, renderAgentList,
  renderContext, renderError, getPromptString, colors,
} from './ui.js';

// ─── Globals ─────────────────────────────────────────────────
let config;
let session;
let context;
let rl;
let isProcessing = false;
let abortSignal = { aborted: false };

// ─── Parse CLI Args ──────────────────────────────────────────
function parseArgs() {
  const args = process.argv.slice(2);
  const opts = { agent: null, resume: false };
  for (let i = 0; i < args.length; i++) {
    switch (args[i]) {
      case '--version': case '-v':
        console.log('magi-code v1.0.0');
        process.exit(0);
        break;
      case '--help': case '-h':
        printUsage();
        process.exit(0);
        break;
      case '--agent': case '-a':
        opts.agent = args[++i];
        break;
      case '--resume': case '-r':
        opts.resume = true;
        break;
    }
  }
  return opts;
}

function printUsage() {
  console.log(`
  MAGI Code — AI coding agent v1.0.0

  Usage: magi [options]

  Options:
    --agent, -a <name>   Start with a specific agent
    --resume, -r         Resume last session
    --version, -v        Show version
    --help, -h           Show this help

  Environment:
    MAGI_API_KEY         API key (default: sk-sentra-magi-2026)
    MAGI_MODEL           Model (default: magi-auto)
    MAGI_API_URL         API endpoint (default: http://127.0.0.1:3005/v1/chat/completions)
`);
}

// ─── Input Loop ──────────────────────────────────────────────
function startInputLoop() {
  rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout,
    prompt: getPromptString(),
    historySize: 100,
    terminal: true,
  });

  rl.prompt();

  rl.on('line', async (line) => {
    const input = line.trim();
    if (!input) { rl.prompt(); return; }

    if (input.startsWith('/')) {
      await handleCommand(input);
    } else {
      await handleMessage(input);
    }
  });

  rl.on('close', () => {
    console.log(colors.dim('\n  Goodbye! 🐱\n'));
    if (session) session.save();
    process.exit(0);
  });

  // Ctrl+C: cancel current stream or hint to exit
  rl.on('SIGINT', () => {
    if (isProcessing) {
      abortSignal.aborted = true;
      console.log(colors.warning('\n  Cancelled.'));
      isProcessing = false;
      rl.prompt();
    } else {
      console.log(colors.dim('\n  Press Ctrl+D to exit, or type /exit'));
      rl.prompt();
    }
  });
}

// ─── Command Handler ─────────────────────────────────────────
async function handleCommand(input) {
  const parts = input.split(/\s+/);
  const cmd = parts[0].toLowerCase();
  const args = parts.slice(1).join(' ');

  switch (cmd) {
    case '/help':
      renderHelp();
      break;

    case '/agent':
      if (!args) {
        console.log(colors.warning('  Usage: /agent <name>'));
        console.log(colors.dim('  Use /agents to see available agents'));
      } else {
        const agentId = args.toLowerCase();
        if (config.agents[agentId]) {
          config.agent = agentId;
          const a = config.agents[agentId];
          console.log(colors.success(`\n  Switched to ${a.emoji} ${a.name} — ${a.role}\n`));
        } else {
          console.log(colors.error(`  Unknown agent: ${args}`));
          console.log(colors.dim('  Use /agents to see available agents'));
        }
      }
      break;

    case '/agents':
      renderAgentList(config.agents, config.agent);
      break;

    case '/context':
      renderContext(session.getContextFiles(), session.estimateTokens());
      break;

    case '/undo': {
      const result = performUndo();
      if (result) {
        console.log(colors.success(`\n  Undo: ${result.path} — ${result.action}\n`));
      } else {
        console.log(colors.warning('\n  Nothing to undo.\n'));
      }
      break;
    }

    case '/clear': {
      const count = session.clear();
      console.log(colors.success(`\n  Cleared ${count} messages.\n`));
      break;
    }

    case '/compact': {
      const compacted = session.compact();
      if (compacted > 0) {
        console.log(colors.success(`\n  Compacted ${compacted} messages.\n`));
      } else {
        console.log(colors.dim('\n  Not enough messages to compact.\n'));
      }
      break;
    }

    case '/resume': {
      const resumed = session.resume();
      if (resumed) {
        console.log(colors.success(`\n  Resumed session from ${resumed.startedAt}`));
        console.log(colors.dim(`  ${session.messages.length} messages loaded\n`));
      } else {
        console.log(colors.warning('\n  No previous session found.\n'));
      }
      break;
    }

    case '/exit':
      session.save();
      console.log(colors.dim('\n  Session saved. Goodbye! 🐱\n'));
      process.exit(0);
      break;

    default:
      console.log(colors.warning(`  Unknown command: ${cmd}`));
      console.log(colors.dim('  Type /help for available commands'));
  }

  rl.prompt();
}

// ─── Message Handler ─────────────────────────────────────────
async function handleMessage(input) {
  isProcessing = true;
  abortSignal = { aborted: false };

  try {
    await sendMessage(config, session, input, {
      onToolConfirm: (summary) => {
        return new Promise((resolve) => {
          rl.question(
            '  ' + colors.dim('└ ') + colors.warning(`Allow ${summary}? `) + colors.dim('[Y/n] '),
            (answer) => {
              const a = answer.trim().toLowerCase();
              resolve(a === '' || a === 'y' || a === 'yes');
            }
          );
        });
      },
      abortSignal,
    });
  } catch (err) {
    renderError(err.message);
  }

  isProcessing = false;
  console.log();
  rl.prompt();
}

// ─── Main ────────────────────────────────────────────────────
async function main() {
  const opts = parseArgs();

  // Load configuration
  config = loadConfig();

  // Override agent from CLI
  if (opts.agent) {
    const agentId = opts.agent.toLowerCase();
    if (config.agents[agentId]) {
      config.agent = agentId;
    } else {
      console.log(colors.warning(`Unknown agent: ${opts.agent}, using default`));
    }
  }

  // Initialize session
  session = new SessionManager(config.magiDir);
  if (opts.resume) {
    if (!session.resume()) session.newSession();
  } else {
    session.newSession();
  }

  // Initialize context
  context = new ContextBuilder(config.projectDir, config.ignorePatterns);

  // Check for API key
  renderWelcome(config);
  if (!config.apiKey) {
    console.log(colors.warning('  ⚠️  No API key configured!'));
    console.log(colors.dim('  Set: export MAGI_API_KEY=your-key\n'));
  }

  // Start input loop
  startInputLoop();
}

// ─── Run ─────────────────────────────────────────────────────
main().catch((err) => {
  console.error(`Fatal: ${err.message}`);
  process.exit(1);
});

